// // This module implements a 1-bit D flip-flop where the output is set to the data input on each rising edge of the clock, regardless of the reset state.
module d_flip_flop(
    input d,
    input clk,
    input reset,
    output reg q
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        q <= 1'b0;
    end else begin
        q <= d;
    end
end

endmodule
